from fastapi import FastAPI, Depends, HTTPException, status
from fastapi.security import OAuth2PasswordBearer
from typing import Optional
import redis
import os

app = FastAPI()

oauth2_scheme = OAuth2PasswordBearer(tokenUrl="token")

r = redis.Redis(host=os.environ.get("REDIS_HOST", "localhost"), port=os.environ.get("REDIS_PORT", 6379))


def get_current_user(token: str = Depends(oauth2_scheme)) -> Optional[str]:
    user_in_cache = r.get(token)

    if not user_in_cache:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": "Bearer"},
        )
        
    return user_in_cache.decode("utf-8")

    
@app.get("/protected_endpoint", dependencies=[Depends(get_current_user)])
async def read_protected_endpoint():
    return {"message": "Welcome to the Protected Endpoint!"}